THE RISK:
{
 "id": "europe-share-phantom-multiplier",
 "title": "The 'Europe ≈ 30%' step in the TAM chain is a number nobody published — the whole funnel hangs on an invented multiplier",
 "narrative": "tamBase is derived as Global $2.81B × Europe ≈ 30% × CE 39.8%. The middle factor is the load-bearing one, and the cited GVR source states only North America's 38% share — no source in the corpus states Europe's rack-PDU share at all. With NA at 38% and APAC absorbing the fastest hyperscale buildout, Europe's true share of a rack-PDU market whose growth is capacity-led could plausibly sit at 20–25%. A hostile diligence partner strikes the 30% first because it is the only unattributed factor in an otherwise sourced expression, and every downstream node — SAM, YAM, every geo and segment slice — scales linearly with it.",
 "category": "fact",
 "targetNodes": [
  "tamBase"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "The derivation's 'Europe ≈ 30% [est.]' factor is flagged in the corpus as unsourced: GVR publishes only NA = 38%, and no retrieved source states a Europe rack-PDU share",
   "refs": [
    "digest:tam-global-crosscheck#c1",
    "digest:tam-base#c1",
    "ledger:tamBase"
   ]
  },
  {
   "step": "propagation",
   "text": "Global publisher estimates for the base itself already span >2x ($1.7B–$3.94B), so an invented regional split compounds on an unstable base; if Europe is 22–25% (consistent with capacity-led demand concentrating in NA/APAC AI builds), the €775M Europe base falls to €570–650M before the CE step is applied",
   "refs": [
    "digest:tam-global-crosscheck#c0",
    "digest:tam-global-crosscheck#c4",
    "ledger:tamBase"
   ]
  },
  {
   "step": "model-impact",
   "text": "tamBase re-derives to roughly €230–260M — below the curated €320M and near the band's low edge for a structural reason the band does not encode (the band was framed as source dispersion, not as a phantom multiplier); SAM and YAM scale down proportionally",
   "refs": [
    "ledger:tamBase",
    "ledger:serviceableFactor",
    "ledger:obtainableFactor"
   ]
  }
 ],
 "whyMissable": "The derivation expression looks fully sourced — every other factor carries a named publisher and date, so the '≈30% [est.]' reads as one more citation rather than the single invented number in the chain. The founder's team sees a triangulated-looking formula, not a formula with a hole in the middle.",
 "expectedObviousness": "medium",
 "falsifier": "A directly sourced Europe rack-PDU revenue share ≥28% — e.g., the IndexBox EU rack-PDU country tables or an Omdia regional vendor-revenue split showing Europe at or above the assumed level.",
 "likelihood": {
  "value": 0.4,
  "rationale": "The corpus explicitly confirms no source states Europe's share, and NA=38% plus documented APAC/NA AI-capacity concentration makes a sub-30% Europe share at least as likely as 30%+; but Europe's dense colo base could also support the assumed level [evidence revision: The trigger premise is confirmed: GVR publishes NA=38% and no retrieved source states an explicit Europe rack-PDU share, so the 30% is genuinely unattributed. However, the falsifier region (paywalled IndexBox EU / Omdia / BIS reports) could plausibly contain a Europe share at or above 30%, and none was retrieved either way. With NA=38% and APAC fastest-growing, a residual for Europe near or below 30% is plausible but not established. No basis to move from the evidence-grounded 0.4.]",
  "basis": "evidence",
  "revisedFrom": 0.4
 },
 "perturbation": [
  {
   "nodeId": "tamBase",
   "op": "set",
   "value": 235,
   "note": "Europe share re-set to ~23% of global instead of 30%; CE step unchanged"
  }
 ],
 "indicators": [
  {
   "signal": "EMEA share of rack-power / critical-infrastructure segment revenue disclosed by Vertiv and Schneider",
   "where": "Vertiv 10-K segment disclosures and Schneider Electric annual report, Energy Management segment regional split",
   "threshold": "EMEA consistently <25% of relevant segment revenue",
   "updates": "increases"
  },
  {
   "signal": "Headline EU rack-PDU market size once the directly-scoped report is opened",
   "where": "IndexBox 'Rack PDUs Market in the European Union' report (currently paywalled, named in the ledger's promotion path)",
   "threshold": "EU figure implying Europe <27% of the GVR global base",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Commission the IndexBox EU rack-PDU report (country tables) to replace the invented regional split with a directly-scoped EU base",
   "type": "information",
   "voiNodeId": "tamBase",
   "note": "Named in the ledger's own promotion path; collapses the ±40% band and kills or confirms this hypothesis in one purchase"
  },
  {
   "action": "Rebuild tamBase bottom-up as CE colocation MW × PDU content €/MW, bypassing the global→Europe→CE scope-down entirely",
   "type": "operational",
   "voiNodeId": null,
   "note": "Uses the Statista MW data already in the ledger plus a per-rack PDU price point; independent of any regional revenue split"
  }
 ],
 "evidenceStatus": "speculative",
 "evidence": [
